blocks.value:
.counter-value {
  font: 800 160px/1 "Pretendard Variable", sans-serif;
  color: #fff;
  font-variant-numeric: tabular-nums;
}
.counter-suffix {
  font: 600 56px/1 "Pretendard Variable", sans-serif;
  color: rgba(255,255,255,0.5);
}

// 오가닉 이징: 초반 빠르게(0~30%) → 중반 보통(30~70%) → 후반 느리게(70~100%)
function organicEase(t) {
  if (t < 0.3) return t * 2.33;   // 빠른 구간
  if (t < 0.7) return 0.7 + (t - 0.3) * 0.5; // 보통
  return 0.9 + (t - 0.7) * 0.333; // 느린 마무리
}
var value = Math.round(organicEase(progress) * 100);

.counter-value {
  font: 700 140px/1 "Pretendard Variable", sans-serif;
  color: #fff;
  font-variant-numeric: tabular-nums;
  letter-spacing: -0.02em;
}

var TARGET = 10000;
function applyReveal(p) {
  valEl.textContent = Math.floor(p * TARGET).toLocaleString("ko-KR");
}

.odo-digit { height: 1em; overflow: hidden;
  font: 800 150px/1 "Pretendard Variable", sans-serif; }
.odo-strip { transition: transform 0.1s ease-out;
  font-variant-numeric: tabular-nums; }

var val = Math.floor(progress * TARGET);
var str = String(val).padStart(4, "0");
digits.forEach(function(d) {
  var pos = parseInt(d.dataset.pos);
  var digitVal = parseInt(str[3 - pos]);
  strip.style.transform = "translateY(-" + (digitVal * 100) + "%)";
});

.counter-value {
  font: 800 130px/1 "Pretendard Variable", sans-serif;
  font-variant-numeric: tabular-nums;
  min-width: 5ch; text-align: right;
}

var TARGET = 1000000;
function easeOutExpo(t) {
  return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
}
var value = Math.floor(easeOutExpo(progress) * TARGET);
valEl.textContent = value.toLocaleString("ko-KR");

.counter-value {
  font: 800 150px/1 "Pretendard Variable", sans-serif;
  font-variant-numeric: tabular-nums;
}

function abbreviate(n) {
  if (n >= 1000000) return (n/1000000).toFixed(1) + "M";
  if (n >= 1000) return (n/1000).toFixed(1) + "K";
  return String(n);
}
var value = Math.floor(progress * TARGET);
valEl.textContent = abbreviate(value);

.counter-value {
  font: 800 160px/1 "Pretendard Variable", sans-serif;
  font-variant-numeric: tabular-nums;
  transition: color 0.05s linear;
}

function lerpColor(a, b, t) {
  return "rgb(" +
    Math.round(a[0]+(b[0]-a[0])*t) + "," +
    Math.round(a[1]+(b[1]-a[1])*t) + "," +
    Math.round(a[2]+(b[2]-a[2])*t) + ")";
}
var C1=[59,130,246], C2=[249,115,22]; // 파랑→주황
var color = lerpColor(C1, C2, progress);

.circle-svg { transform: rotate(-90deg); }
.circle-bg { fill: none; stroke: rgba(255,255,255,0.08); stroke-width: 8; }
.circle-fg { fill: none; stroke: #3b82f6; stroke-width: 8;
  stroke-linecap: round;
  stroke-dasharray: 553; stroke-dashoffset: 553; }

var CIRC = 2 * Math.PI * 88; // ≈ 553
fg.style.strokeDashoffset = CIRC * (1 - progress);
valEl.textContent = Math.round(progress * 100);

.bar-track { height: 8px; background: rgba(255,255,255,0.08);
  border-radius: 4px; overflow: hidden; }
.bar-fill { height: 100%; width: 0; background: #3b82f6;
  border-radius: 4px; transition: width 0.05s linear; }

rows.forEach(function(row, i) {
  var target = parseInt(fill.dataset.target);
  var stagger = Math.max(0, (p - i*0.08) / (1 - i*0.08));
  fill.style.width = stagger * target + "%";
  pct.textContent = Math.round(stagger * target) + "%";
});

.counter-value {
  font: 800 160px/1 "Pretendard Variable", sans-serif;
  font-variant-numeric: tabular-nums;
}

function springEase(t) {
  var w = 4.5 * Math.PI; // 진동 주파수
  return 1 - Math.exp(-6*t) * Math.cos(w * t);
}
var value = Math.round(springEase(progress) * TARGET);
// overshoot 시 scale 살짝 증가
var scale = 1 + Math.abs(springEase(p) - p) * 0.08;

.stat-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 48px; }
.stat-value { font: 800 64px/1 "Pretendard Variable", sans-serif;
  font-variant-numeric: tabular-nums; }
.stat-label { font: 400 15px/1.4 "Pretendard Variable", sans-serif;
  color: rgba(255,255,255,0.3); letter-spacing: 0.1em; }

cards.forEach(function(card, i) {
  var target = parseInt(card.dataset.target);
  var stagger = clamp01((p - i*0.1) / 0.7);
  var v = Math.round(easeOutCubic(stagger) * target);
  card.querySelector(".stat-value").textContent = v.toLocaleString();
  card.style.opacity = Math.min(1, stagger * 3);
  card.style.transform = "translateY(" + ((1-clamp01(stagger*2))*16) + "px)";
});
